    }

    ForumTag tag = new ForumTag();
    tag.setName(name);
    tag.setIsSystem(isSystem);
    tag = tagRepository.save(tag);

    return toDTO(tag);
}

private ForumTagDTO toDTO(ForumTag tag) {
    return new ForumTagDTO(tag.getId(), tag.getName(), tag.getPostCount(), tag.getIsSystem());
}

