async fetchPosts(params?: {
      category?: number;
      tag?: number;
      keyword?: string;
      page?: number;
      size?: number;
    }) {
      this.loading = true;
      try {
        const response = await forumService.getPostList(params);
        this.posts = response.content;
        this.pagination = {
          page: response.number,
          size: response.size,
          totalElements: response.totalElements,
          totalPages: response.totalPages
        };
      } finally {
        this.loading = false;
      }
    }

